import type { Metadata } from 'next';
import { notFound } from 'next/navigation';
import { BackButton } from '@/components/BackButton';

type Post = {
  id: number;
  title: string;
  body: string;
};

type Comment = {
  id: number;
  name: string;
  body: string;
  email: string;
};

type PageProps = {
  params: Promise<{
    id: string;
  }>;
};

export const revalidate = 300;

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts');

  if (!response.ok) {
    return [];
  }

  const posts = (await response.json()) as Post[];

  return posts.slice(0, 10).map((post) => ({ id: post.id.toString() }));
}

async function getPost(id: string): Promise<Post> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate: 300 },
  });

  if (!response.ok) {
    notFound();
  }

  const post = (await response.json()) as Partial<Post>;

  if (!post.id || !post.title || !post.body) {
    notFound();
  }

  return post as Post;
}

async function getComments(id: string): Promise<Comment[]> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });

  if (!response.ok) {
    throw new Error('Failed to fetch comments');
  }

  return response.json() as Promise<Comment[]>;
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);
  const description = post.body.substring(0, 160);

  return {
    title: post.title,
    description,
    openGraph: {
      title: post.title,
      description,
    },
  };
}

export default async function BlogPostPage({ params }: PageProps) {
  const { id } = await params;
  const [post, comments] = await Promise.all([getPost(id), getComments(id)]);

  return (
    <article>
      <BackButton />

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}
